#include <bits/stdc++.h>
using namespace std;
int main(){
    int m, n;
    if(!(cin >> m >> n)) return 0;
    vector<int> matrix(m * n);
    for(int i = 0; i < m * n; i++) cin >> matrix[i];
    int target; cin >> target;
    int low = 0, high = m * n - 1;
    while(low <= high){
        int mid = (low + high) / 2;
        if(matrix[mid] == target){
            cout << "true" << endl;
            return 0;
        }
        else if(matrix[mid] < target){
            low = mid + 1;
        }
        else{
            high = mid - 1;
        }
    }
    cout << "false" << endl;
    return 0;
}
